import React, { useEffect, useState } from "react";
import axiosInstance from "../lib/instance";

function Store() {
  const [stores, setStores] = useState([]);
  const [loading, setLoading] = useState(false);

  // ✅ Fetch stores
  const fetchStores = async () => {
    setLoading(true);
    try {
      const res = await axiosInstance.get("/stores/all"); // adjust endpoint if needed

      console.log("Stores:", res.data);

      if (res?.data?.stores) {
        setStores(res.data.stores);
      }
    } catch (error) {
      console.error("Fetch stores error:", error);
    } finally {
      setLoading(false);
    }
  };

  // ✅ Load on mount
  useEffect(() => {
    fetchStores();
  }, []);

  // ✅ Stats
  const totalStores = stores.length;
  const totalRatings = stores.reduce(
    (acc, s) => acc + (s?.rating || 0),
    0
  );

  return (
    <div>
      {/* Stats */}
      <div className="grid grid-cols-3 gap-4 mb-6">
        <div className="bg-white p-4 rounded shadow">
          Stores: {totalStores}
        </div>
        <div className="bg-white p-4 rounded shadow">
          Ratings: {totalRatings}
        </div>
      </div>

      {/* Table */}
      <div className="bg-white p-4 rounded shadow">
        <h2 className="font-semibold mb-3">Stores</h2>

        {loading ? (
          <p>Loading...</p>
        ) : (
          <table className="w-full text-center">
            <thead className="bg-indigo-600 text-white">
              <tr>
                <th>Name</th>
                <th>Email</th>
                <th>Address</th>
                <th>Rating</th>
              </tr>
            </thead>

            <tbody>
              {stores.length > 0 ? (
                stores.map((s) => (
                  <tr key={s.id} className="border-b">
                    <td>{s.name}</td>
                    <td>{s.email}</td>
                    <td>{s.address}</td>
                    <td>{s.rating || 0}</td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="4">No stores found</td>
                </tr>
              )}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}

export default Store;
